        let count = 0;

        for (let key in enrichedVars) {
            if (key === "enrichedVars"|| key=== "ipListe") continue; // ne pas recréer enrichedVars lui-même

            const varData = enrichedVars[key];
            if (!varData || typeof varData !== "object") continue;

            const type = varData.typeVarG || "string";
            let value;

            if (type === "object" && varData.etat !== undefined) {
                value = varData.etat;
            } else {
                const raw = varData.valeurCouranteVarG;
                switch (type) {
                    case "number":
                        value = parseFloat(raw);
                        break;
                    case "boolean":
                        value = (raw === "true");
                        break;
                    case "string":
                    default:
                        value = raw;
                        break;
                }
            }

            global.set(key, value, storeDefault);
            count++;
        }

        node.status({ fill: "green", shape: "dot", text: `✔️ Restauré ${count} variables` });
