// 🔄 Fonction utilitaire pour les valeurs par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

const storeDefault = "default";
const storeFile = "file";

// Supprimer enrichedVars du stockage par défaut
global.set("enrichedVars", undefined, storeDefault);

// Récupération des variables globales du stockage par défaut
const allKeys = global.keys(storeDefault) || [];
let globalVars = {};
allKeys.forEach(key => {
    if (key !== "enrichedVars") {
        const val = global.get(key, storeDefault);
        globalVars[key] = (typeof val === "object") ? JSON.parse(JSON.stringify(val)) : val;
    }
});

// Chargement de enrichedVars depuis le stockage fichier
let enrichedVars = global.get("enrichedVars", storeFile) || {};

// 🔄 Conversion utile (string => typed)
function convertFromString(value, type) {
    if (value === null || value === undefined) return defaultForType(type);
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        return defaultForType(type);
    }
}

// 🔄 Conversion utile (typed => string ou JSON)
function convertToString(value, type) {
    if (value === null || value === undefined) return "";
    try {
        switch (type) {
            case "array":
            case "object":
                return JSON.stringify(value);
            default:
                return String(value);
        }
    } catch (err) {
        return String(value);
    }
}

