// Ce nœud synchronise les variables globales avec enrichedVars.
// Il met à jour enrichedVars avec les variables globales actuelles
// et s'assure que chaque variable suit la nouvelle structure définie.
// Les variables sont stockées dans deux types de stockage : "default" et "file".
// Les variables sont structurées avec des propriétés comme nomVarG, typeVarG, instances, detailEtat, etc.
// La fonction gère également la restauration des variables globales manquantes depuis enrichedVars.
// Elle prend en compte les instances et les sous-variables pour une synchronisation cohérente.

func:
// 🔄 Fonction utilitaire pour les valeurs par défaut selon le type
function defaultForType(type) {
    switch (type) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

// Stores utilisés
const storeDefault = "default";
const storeFile = "file";

// 1️⃣ - Nettoyer toutes les variables du store "default"
(global.keys(storeDefault) || []).forEach(k => {
    global.set(k, undefined, storeDefault);
});

// 2️⃣ - Récupérer enrichedVars depuis le fichier
let enrichedVars = global.get("enrichedVars", storeFile) || {};

// 3️⃣ - Conversion : string → typé
function convertFromString(value, type) {
    if (value === null || value === undefined) return defaultForType(type);
    try {
        switch (type) {
            case "int": return parseInt(value, 10);
            case "number": return parseFloat(value);
            case "boolean": return (value === true || value === "true");
            case "string": return String(value);
            case "array": return Array.isArray(value) ? value : JSON.parse(value);
            case "object": return typeof value === "object" ? value : JSON.parse(value);
            case "date": return new Date(value);
            default: return value;
        }
    } catch (err) {
        return defaultForType(type);  // Valeur par défaut en cas d'erreur
    }
}

// 4️⃣ - Restaurer toutes les variables dans le store "default"
Object.entries(enrichedVars).forEach(([key, e]) => {
    const instances = e.instances || [];
    const props = e.proprietesByInstance?.proprietes || [];
    const valeurs = e.proprietesByInstance?.valeurs || {};
    let variable = {};

    // Initialiser les schémas pour les objets
    props.forEach(p => {
        if (p.type === "object" && !p.schema) {
            p.schema = {};
        }
    });

    // Remplissage des instances
    instances.forEach(instance => {
        variable[instance] = {};
        props.forEach(prop => {
            const name = prop.nom;
            const type = prop.type;
            const rawValue = valeurs?.[instance]?.[name];
            variable[instance][name] = convertFromString(rawValue, type);
            if (prop.abbr) {
                if (!variable._abbrProprietes) variable._abbrProprietes = {};
                variable._abbrProprietes[name] = prop.abbr;
            }
        });
    });

    // Ajout des métadonnées globales
    if (e.abbrVarG) variable._abbrVarG = e.abbrVarG;
    if (e.indexInstances) variable._indexInstances = e.indexInstances;

    // Sauvegarde dans memoryOnly
    if (instances.length === 1 && instances[0] === "*") {
        global.set(key, variable["*"], storeDefault);
    } else {
        global.set(key, variable, storeDefault);
    }
});

// 5️⃣ - Fin
msg.payload = enrichedVars;
msg.info = "✅ Initialisation enrichie depuis enrichedVars (file) terminée.";
return msg;

