// 🔁 Fonction : Convertit depuis JSON (stockage file) vers types JS
function convertValue(type, value) {
    try {
        switch (type) {
            case "int":
                return parseInt(value, 10);
            case "float":
                return parseFloat(value);
            case "boolean":
                return (value === true || value === "true");
            case "array":
                if (Array.isArray(value)) return value;
                const parsed = JSON.parse(value);
                return Array.isArray(parsed) ? parsed : [];
            case "string":
            default:
                return String(value);
        }
    } catch (err) {
        node.warn(`Erreur convertValue(${type}) : ${err.message}`);
        return null;
    }
}

// 🔁 Fonction : Convertit depuis JS (dashboard) vers JSON (stockage file)
function revertValue(type, value) {
    try {
        switch (type) {
            case "int":
                return parseInt(value, 10);
            case "float":
                return parseFloat(value);
            case "boolean":
                return Boolean(value);
            case "array":
                return JSON.stringify(Array.isArray(value) ? value : []);
            case "string":
            default:
                return String(value);
        }
    } catch (err) {
        node.warn(`Erreur revertValue(${type}) : ${err.message}`);
        return "";
    }
}

// 🔧 Exemple : Synchroniser enrichedVars["leds"]
