        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
}

const storeDefault = "default";
const storeFile = "file";
const allKeys = global.keys(storeDefault) || [];
let enrichedVars = global.get("enrichedVars", storeFile) || {};

// 🔄 Conversion utile : typé → string/JSON
function convertToString(value, type) {
    if (value === null || value === undefined) return "";
    try {
        switch (type) {
            case "array":
            case "object":
                return JSON.stringify(value);
            case "boolean":
                return value ? "true" : "false";
            case "date":
                return new Date(value).toISOString();
            default:
                return String(value);
        }
    } catch (err) {
