    }
}

// ⏺️ Export des variables en enrichedVars
allKeys.forEach(key => {
    if (key === "enrichedVars") return;
    const val = global.get(key, storeDefault);
    const type = typeof val;

    // Cas des objets avec instances
    if (type === "object" && val && !Array.isArray(val)) {
        const instances = Object.keys(val);
        if (instances.length === 0) return;

        const firstInstance = val[instances[0]];
        if (typeof firstInstance === "object") {
            const props = Object.keys(firstInstance);
            const propDefs = props.map(p => {
