// Helpers
const toArray = (v) => {
    if (Array.isArray(v)) return v;
    if (typeof v === "string") {
        const s = v.trim();
        if (!s) return [];
        return s.includes(",") ? s.split(",").map(x => x.trim()).filter(Boolean) : [s];
    }
    return [];
};

const deepClone = (o) => JSON.parse(JSON.stringify(o || {}));

const defaultForType = (t) => {
    switch (t) {
        case "boolean": return false;
        case "int": case "number": return 0;
        case "array": return [];
        case "object": return {};
        case "date": return new Date().toISOString().slice(0, 10);
        default: return "";
    }
};

// Instances → toujours Array
let instances = toArray(variable.instances || ["*"]);

// Propriétés → nettoyage et validation
let propArr = [];
if (variable.proprietesByInstance?.proprietes) {
    propArr = variable.proprietesByInstance.proprietes
        .filter(p => p && typeof p.nom === "string" && typeof p.type === "string")
        .map(p => ({
            nom: String(p.nom),
            type: String(p.type),
            schema: p.schema || (p.type === "object" ? {} : undefined)  // ⭐ Initialisation du schéma pour les objets
        }));
}

// Abréviations des propriétés
let abbrMap = {};
if (variable.proprietesByInstance?.abbrProprietes && typeof variable.proprietesByInstance.abbrProprietes === "object") {
    abbrMap = deepClone(variable.proprietesByInstance.abbrProprietes);
}

// Valeurs → désérialisation des objets/tableaux
let valeursRaw = deepClone(variable.proprietesByInstance?.valeurs || {});
let valeurs = {};
instances.forEach(inst => {
