                value = JSON.parse(storedValue);  // ⭐ Désérialisation des objets
            } else if (p.type === "array" && typeof storedValue === "string") {
                value = JSON.parse(storedValue);  // ⭐ Désérialisation des tableaux
            } else if (p.type === "boolean") {
                value = storedValue === true || storedValue === "true";
            } else if (p.type === "int" || p.type === "number") {
                value = parseFloat(storedValue) || 0;
            }
        } catch (e) {
            console.warn(`Désérialisation échouée pour ${p.nom}:`, e);
            value = defaultForType(p.type);  // Valeur par défaut en cas d'erreur
        }
        valeurs[inst][p.nom] = value !== undefined ? value : defaultForType(p.type);
    });
});

