function testCondition(cond, varG) {
    const { var: varName, instance, property, operator, value } = cond;
    const val = varG[varName]?.[instance]?.[property];
    switch (operator) {
        case "==": return val === value;
        case "!=": return val !== value;
        case ">": return val > value;
        case "<": return val < value;
        case ">=": return val >= value;
        case "<=": return val <= value;
        default: return false;
    }
}

const varG = global.get("enrichedVars") || {};
const outputMsgs = [];

for (const rule of rules) {
    if (!rule.enabled) continue;

    const allConditionsOK = rule.conditions.every(cond => testCondition(cond, varG));

    if (allConditionsOK) {
        for (const action of rule.actions) {
            const outMsg = {
                payload: action.value || action.payload || null,
                topic: action.topic || null,
                info: action.info || `Action de la règle: ${rule.name}`,
                ruleId: rule.id,
                ruleName: rule.name,
                actionType: action.type,
                target: action.target
            };
            outputMsgs.push(outMsg);
        }
    }
}

return [outputMsgs];

